class Solution(object):
    def countDaysTogether(self, arriveAlice, leaveAlice, arriveBob, leaveBob):
        days = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
        def dayOfYear(date):
            month, day = int(date[:2]), int(date[3:])
            return sum(days[:month-1]) + day
        alice_start = dayOfYear(arriveAlice)
        alice_end = dayOfYear(leaveAlice)
        bob_start = dayOfYear(arriveBob)
        bob_end = dayOfYear(leaveBob)
        overlap_start = max(alice_start, bob_start)
        overlap_end = min(alice_end, bob_end)
        return max(0, overlap_end - overlap_start + 1)
